export const KNOWN_SILENT_HOLES: readonly KnownHole[] = RAW_HOLES.trim()
  .split("\n")
  .map((line) => {
    const [siteId, kind, fingerprint, finding, ...noteParts] = line.split("|");
    return {
      siteId: siteId!,
      kind: kind as Alarm["kind"],
      fingerprint: fingerprint!,
      finding: finding!,
      note: noteParts.join("|"),
    };
  });
